code = """import json

# Load data
opp_lines = locals()['var_function-call-5956558121782651317']
price_entries = locals()['var_function-call-5956558121782649872']

# Helper to clean ID
def clean_id(id_str):
    if id_str and id_str.startswith('#'):
        return id_str[1:]
    return id_str

# Create Price Map
price_map = {}
for entry in price_entries:
    pid = clean_id(entry['Id'])
    try:
        price = float(entry['UnitPrice'])
        price_map[pid] = price
    except:
        pass

# Calculate Sales per Agent
agent_sales = {}

for line in opp_lines:
    owner = line['OwnerId']
    pid = clean_id(line['PricebookEntryId'])
    try:
        qty = float(line['Quantity'])
    except:
        qty = 0.0
    
    if pid in price_map:
        unit_price = price_map[pid]
        amount = qty * unit_price
        
        if owner not in agent_sales:
            agent_sales[owner] = 0.0
        agent_sales[owner] += amount

# Find Top Agent
top_agent = None
max_sales = -1.0

for agent, sales in agent_sales.items():
    if sales > max_sales:
        max_sales = sales
        top_agent = agent

print("__RESULT__:")
print(json.dumps(top_agent))"""

